from abc import ABC, abstractmethodclass Position :     column: str    row: int        def __init__(self, column, row):        self.column = column        self.row = row            #pour renvoyer la position en string    def __str__(self):        return f"{self.column}{self.row}"class Player :    name: str    color: int    elo: int    nationality: str        def __init__(self, name, color):        self.name = name        self.color = color            def askMove(self):        move = str(input("Quel déplacement voulez-vous faire : "))        print(move)class Board():    def getPosition(self, piece):        #a faire        return piece.position        def getPiece(self, position):        return self.grid[f"{position}"]        def __init__(self):        #on utilise un dictionnaire avec comme clé la position en str et qui contient la piece        self.grid = {}                for color in [0, 1]:                        row1 = 1 if color == 0 else 8            row2 = 2 if color == 0 else 7                        self.grid[f"a{row1}"] = Tour(Position("a", row1), color)            self.grid[f"b{row1}"] = Cavalier(Position("b", row1), color)            self.grid[f"c{row1}"] = Fou(Position("c", row1), color)            self.grid[f"d{row1}"] = Reine(Position("d", row1), color)            self.grid[f"e{row1}"] = Roi(Position("e", row1), color)            self.grid[f"f{row1}"] = Fou(Position("f", row1), color)            self.grid[f"g{row1}"] = Cavalier(Position("g", row1), color)            self.grid[f"h{row1}"] = Tour(Position("h", row1), color)                        for column in ["a", "b", "c", "d", "d", "f", "g", "h"]:                self.grid[f"{column}{row2}"] = Pion(Position(column, row2), color)        class Piece(ABC):        position: Position    color: int        def __init__(self, position, color):        self.position = position        self.color = color        @abstractmethod    def isValidMove():        pass        class Roi(Piece):        def __str__():        return "K"        def isValidMove(newPosition, board):        #a définir        pass    class Reine(Piece):        def __str__():        return "Q"        def isValidMove(newPosition, board):        #a définir        pass    class Fou(Piece):        def __str__():        return "B"        def isValidMove(newPosition, board):        #a définir        passclass Tour(Piece):        def __str__():        return "R"        def isValidMove(newPosition, board):        #a définir        pass    class Pion(Piece):        def __str__():        return "P"        def isValidMove(newPosition, board):        #a définir        pass    class Cavalier(Piece):        def __str__():        return "N"        def isValidMove(newPosition, board):        #a définir        passclass Chess():    board: Board    players: list[Player]    currentPlayer: Player        def initPlayers(self):        print("--- Intialisation des joueurs ---")        print("")        print("Joueur 1 : \nEntrez votre nom :")                name1 = str(input(""))                print("")        print("Joueur 2 : \nEntrez votre nom :")                name2 = str(input(""))                player1 = Player(name1, 0)        player2 = Player(name2, 1)                self.players = [player1, player2]        def displayBoard(self):        #a faire        pass        def isValidMove(self, move):        return True        def isCheckMate(self):        return False        def updateBoard(self):        # a faire        pass        def switchPlayer(self):        #a faire        pass        def play(self):        self.board = Board()        pass